"""Elite branded workout workbook generator.

This script builds a premium, multi-sheet Excel system with polished visual design,
strong data validation, dashboard analytics, and long-term logging structure.

Usage:
    python Main.py
    python Main.py --output "Ethan_Elite_Workout_System.xlsx"
"""

from __future__ import annotations

import argparse
from datetime import date, timedelta
from statistics import mean

from openpyxl import Workbook
from openpyxl.chart import BarChart, LineChart, PieChart, Reference
from openpyxl.formatting.rule import ColorScaleRule, DataBarRule, FormulaRule, IconSetRule
from openpyxl.styles import Alignment, Border, Font, GradientFill, PatternFill, Side
from openpyxl.worksheet.datavalidation import DataValidation

# =========================
# BRANDING + THEME
# =========================
BRAND_NAME = "ETHAN ELITE PERFORMANCE"
TAGLINE = "Discipline. Precision. Relentless Progress."

BRAND_NAVY = "0B132B"
BRAND_BLUE = "1C2541"
BRAND_STEEL = "3A506B"
BRAND_CYAN = "5BC0BE"
BRAND_WHITE = "FFFFFF"
BRAND_SILVER = "E5E7EB"
BRAND_DARK = "111827"
BRAND_LIGHT = "F8FAFC"
BRAND_GREEN = "059669"
BRAND_RED = "DC2626"
BRAND_GOLD = "F59E0B"
BRAND_PURPLE = "7C3AED"
BRAND_SKY = "0EA5E9"
BRAND_MINT = "10B981"

THIN = Side(style="thin", color="CBD5E1")
MED = Side(style="medium", color="64748B")
THIN_BORDER = Border(left=THIN, right=THIN, top=THIN, bottom=THIN)
MED_BORDER = Border(left=MED, right=MED, top=MED, bottom=MED)


# =========================
# STYLE UTILITIES
# =========================
def set_workbook_defaults(wb: Workbook) -> None:
    """Set workbook-level defaults where supported."""
    wb.properties.creator = "Ethan Elite Automation"
    wb.properties.title = "Ethan Elite Workout System"
    wb.properties.subject = "Workout planning and tracking"
    wb.properties.description = "Fully-branded elite workout operating system"


def configure_sheet(ws, freeze: str | None = None, zoom: int = 120) -> None:
    ws.sheet_view.showGridLines = False
    ws.sheet_view.zoomScale = zoom
    ws.sheet_properties.tabColor = BRAND_CYAN
    if freeze:
        ws.freeze_panes = freeze


def style_brand_banner(ws, start_row: int = 1, start_col: int = 2, end_col: int = 11) -> None:
    for col in range(start_col, end_col + 1):
        c = ws.cell(row=start_row, column=col)
        c.fill = GradientFill(stop=(BRAND_NAVY, BRAND_BLUE))
        c.border = MED_BORDER

    ws.merge_cells(start_row=start_row, start_column=start_col, end_row=start_row, end_column=end_col)
    banner = ws.cell(row=start_row, column=start_col)
    banner.value = f"{BRAND_NAME} | {TAGLINE}"
    banner.font = Font(name="Calibri", size=14, bold=True, color=BRAND_WHITE)
    banner.alignment = Alignment(horizontal="center", vertical="center")
    ws.row_dimensions[start_row].height = 26


def style_title(ws, cell: str, text: str, subtitle: str | None = None) -> None:
    ws[cell] = text
    ws[cell].font = Font(name="Calibri", size=22, bold=True, color=BRAND_NAVY)
    ws[cell].alignment = Alignment(horizontal="left", vertical="center")

    if subtitle:
        row = ws[cell].row + 1
        col = ws[cell].column
        ws.cell(row=row, column=col, value=subtitle)
        ws.cell(row=row, column=col).font = Font(name="Calibri", size=10, italic=True, color=BRAND_STEEL)


def style_section_header(ws, row: int, start_col: int, end_col: int, text: str) -> None:
    ws.merge_cells(start_row=row, start_column=start_col, end_row=row, end_column=end_col)
    c = ws.cell(row=row, column=start_col, value=text)
    c.fill = PatternFill(fill_type="solid", fgColor=BRAND_BLUE)
    c.font = Font(name="Calibri", size=12, bold=True, color=BRAND_WHITE)
    c.alignment = Alignment(horizontal="left", vertical="center")
    for col in range(start_col, end_col + 1):
        ws.cell(row=row, column=col).border = MED_BORDER


def style_headers(ws, row: int, start_col: int, end_col: int) -> None:
    for col in range(start_col, end_col + 1):
        c = ws.cell(row=row, column=col)
        c.fill = PatternFill(fill_type="solid", fgColor=BRAND_DARK)
        c.font = Font(name="Calibri", size=11, bold=True, color=BRAND_WHITE)
        c.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
        c.border = THIN_BORDER


def style_data_cell(cell) -> None:
    cell.border = THIN_BORDER
    cell.font = Font(name="Calibri", size=10, color=BRAND_DARK)
    cell.alignment = Alignment(horizontal="center", vertical="center")


def zebra_rows(ws, start_row: int, end_row: int, start_col: int, end_col: int) -> None:
    for r in range(start_row, end_row + 1):
        if r % 2 == 0:
            for c in range(start_col, end_col + 1):
                ws.cell(row=r, column=c).fill = PatternFill(fill_type="solid", fgColor=BRAND_LIGHT)


def apply_kpi_card(ws, row: int, label_col: int, value_col: int, label: str, formula: str, fmt: str | None = None) -> None:
    ws.cell(row=row, column=label_col, value=label)
    ws.cell(row=row, column=value_col, value=formula)

    l = ws.cell(row=row, column=label_col)
    v = ws.cell(row=row, column=value_col)

    l.fill = PatternFill(fill_type="solid", fgColor="E2E8F0")
    l.font = Font(name="Calibri", bold=True, color=BRAND_BLUE)
    l.border = MED_BORDER
    l.alignment = Alignment(horizontal="left", vertical="center")

    v.fill = PatternFill(fill_type="solid", fgColor=BRAND_WHITE)
    v.font = Font(name="Calibri", size=12, bold=True, color=BRAND_NAVY)
    v.border = MED_BORDER
    v.alignment = Alignment(horizontal="center", vertical="center")
    if fmt:
        v.number_format = fmt


def set_col_widths(ws, widths: dict[str, float]) -> None:
    for col, width in widths.items():
        ws.column_dimensions[col].width = width


