def build_cover_sheet(wb: Workbook) -> None:
    ws = wb.active
    ws.title = "Start Here"
    configure_sheet(ws, zoom=125)
    style_brand_banner(ws, start_row=1, start_col=2, end_col=12)
    style_title(ws, "B3", "Ethan Elite Workout System", subtitle=f"Generated on {date.today().strftime('%B %d, %Y')}")

    ws.merge_cells("B6:F6")
    ws["B6"] = "MISSION"
    ws["B6"].font = Font(size=13, bold=True, color=BRAND_WHITE)
    ws["B6"].fill = PatternFill(fill_type="solid", fgColor=BRAND_PURPLE)
    ws["B6"].alignment = Alignment(horizontal="center")
    ws["B6"].border = MED_BORDER

    ws.merge_cells("B7:F10")
    ws["B7"] = (
        "This system is engineered to be your #1 training command center.\n\n"
        "Track your programming, daily execution, body metrics, recovery, and progressive overload in one place."
    )
    ws["B7"].alignment = Alignment(wrap_text=True, vertical="top")
    ws["B7"].fill = PatternFill(fill_type="solid", fgColor=BRAND_LIGHT)
    ws["B7"].border = MED_BORDER
    ws["B7"].font = Font(size=11, color=BRAND_DARK)

    style_section_header(ws, 12, 2, 8, "How to Win With This System")
    checklist = [
        "1. Customize Program Builder based on your current split.",
        "2. Log every session in Daily Log (no skipped entries).",
        "3. Update Body Metrics weekly at the same time of day.",
        "4. Review Dashboard after each training week.",
        "5. Execute, recover, improve, repeat.",
    ]
    for i, text in enumerate(checklist, start=13):
        ws.cell(row=i, column=2, value=text)
        ws.cell(row=i, column=2).alignment = Alignment(wrap_text=True)
        ws.cell(row=i, column=2).border = THIN_BORDER
        ws.cell(row=i, column=2).fill = PatternFill(fill_type="solid", fgColor="F1F5F9" if i % 2 == 0 else "FFFFFF")

    set_col_widths(ws, {"B": 55, "C": 2, "D": 2, "E": 2, "F": 2, "G": 2, "H": 2, "I": 2, "J": 2, "K": 2, "L": 2})


def build_dashboard(wb: Workbook) -> None:
    ws = wb.create_sheet("Dashboard")
    configure_sheet(ws, zoom=120)
    style_brand_banner(ws, start_row=1, start_col=2, end_col=12)
    style_title(ws, "B3", "Performance Dashboard", subtitle="Real-time KPI view")

    apply_kpi_card(ws, 6, 2, 3, "Planned Sessions", "=COUNTIF('Program Builder'!$C$5:$C$400,\"<>\")")
    apply_kpi_card(ws, 7, 2, 3, "Completed Sessions", "=COUNTIF('Daily Log'!$D$5:$D$2000,\"Yes\")")
    apply_kpi_card(ws, 8, 2, 3, "Completion Rate", "=IFERROR(C7/C6,0)", "0.0%")
    apply_kpi_card(ws, 9, 2, 3, "Avg Session Duration", "=IFERROR(AVERAGE('Daily Log'!$J$5:$J$2000),0)", "0")
    apply_kpi_card(ws, 10, 2, 3, "Avg Session RPE", "=IFERROR(AVERAGE('Daily Log'!$K$5:$K$2000),0)", "0.0")
    apply_kpi_card(ws, 11, 2, 3, "Current Weight", "='Body Metrics'!$C$6", "0.0")
    apply_kpi_card(ws, 12, 2, 3, "Weight Change", "='Body Metrics'!$C$5-'Body Metrics'!$C$6", "0.0")

    style_section_header(ws, 6, 5, 9, "Consistency Signals")
    ws["E7"] = "Last Workout Date"
    ws["F7"] = "=LOOKUP(2,1/('Daily Log'!$B$5:$B$2000<>\"\"),'Daily Log'!$B$5:$B$2000)"
    ws["E8"] = "This Week Sessions"
    ws["F8"] = "=COUNTIFS('Daily Log'!$B$5:$B$2000,\">=\"&TODAY()-WEEKDAY(TODAY(),2)+1,'Daily Log'!$B$5:$B$2000,\"<=\"&TODAY(),'Daily Log'!$D$5:$D$2000,\"Yes\")"
    ws["E9"] = "This Month Sessions"
    ws["F9"] = "=COUNTIFS('Daily Log'!$B$5:$B$2000,\">=\"&EOMONTH(TODAY(),-1)+1,'Daily Log'!$B$5:$B$2000,\"<=\"&EOMONTH(TODAY(),0),'Daily Log'!$D$5:$D$2000,\"Yes\")"
    ws["E10"] = "Avg Sleep"
    ws["F10"] = "=IFERROR(AVERAGE('Recovery Tracker'!$D$5:$D$2000),0)"
    ws["E11"] = "Avg Steps"
    ws["F11"] = "=IFERROR(AVERAGE('Recovery Tracker'!$E$5:$E$2000),0)"
    ws["E12"] = "Avg Calories"
    ws["F12"] = "=IFERROR(AVERAGE('Nutrition'!$E$5:$E$2000),0)"

    for r in range(7, 13):
        ws[f"E{r}"].font = Font(bold=True, color=BRAND_BLUE)
        ws[f"E{r}"].fill = PatternFill(fill_type="solid", fgColor="E2E8F0")
        ws[f"E{r}"].border = MED_BORDER
        ws[f"F{r}"].border = MED_BORDER
        ws[f"F{r}"].alignment = Alignment(horizontal="center")

    ws["F7"].number_format = "mmm d, yyyy"
    ws["F10"].number_format = "0.0"
    ws["F11"].number_format = "#,##0"
    ws["F12"].number_format = "#,##0"

    # Charts
    bar = BarChart()
    bar.title = "Weekly Session Completion"
    bar.y_axis.title = "Sessions"
    bar.x_axis.title = "Week"
    chart_data = Reference(ws, min_col=3, min_row=6, max_row=9)
    chart_labels = Reference(ws, min_col=2, min_row=6, max_row=9)
    bar.add_data(chart_data, titles_from_data=False)
    bar.set_categories(chart_labels)
    bar.height = 7
    bar.width = 12
    ws.add_chart(bar, "H6")

    pie = PieChart()
    pie.title = "Program Distribution"
    pie_data = Reference(ws, min_col=3, min_row=6, max_row=8)
    pie_labels = Reference(ws, min_col=2, min_row=6, max_row=8)
    pie.add_data(pie_data)
    pie.set_categories(pie_labels)
    pie.height = 7
    pie.width = 8
    ws.add_chart(pie, "H15")

    set_col_widths(ws, {"B": 28, "C": 18, "D": 2, "E": 24, "F": 20, "G": 2, "H": 16, "I": 16, "J": 16, "K": 16, "L": 16})


def build_program_builder(wb: Workbook) -> None:
    ws = wb.create_sheet("Program Builder")
    configure_sheet(ws, freeze="B5")
    style_brand_banner(ws, start_row=1, start_col=2, end_col=12)
    style_title(ws, "B3", "Program Builder", subtitle="Design your split, progression, and weekly structure")

    headers = [
        "Week",
        "Day",
        "Session Type",
        "Primary Goal",
        "Exercise",
        "Sets",
        "Target Reps",
        "Target Load",
        "Rest (sec)",
        "Target RPE",
        "Notes",
    ]
    for i, h in enumerate(headers, start=2):
        ws.cell(row=4, column=i, value=h)
    style_headers(ws, 4, 2, 12)

    days = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"]
    types = ["Upper", "Lower", "Push", "Pull", "Legs", "Conditioning", "Recovery", "Full Body"]
    goals = ["Strength", "Hypertrophy", "Power", "Work Capacity", "Technique"]

    for r in range(5, 405):
        week = (r - 5) // 7 + 1
        day = days[(r - 5) % 7]
        ws.cell(row=r, column=2, value=week)
        ws.cell(row=r, column=3, value=day)
        ws.cell(row=r, column=4, value=types[(r - 5) % len(types)])
        ws.cell(row=r, column=5, value=goals[(r - 5) % len(goals)])

        for c in range(2, 13):
            style_data_cell(ws.cell(row=r, column=c))

    zebra_rows(ws, 5, 404, 2, 12)

    session_list = DataValidation(type="list", formula1='"Upper,Lower,Push,Pull,Legs,Conditioning,Recovery,Full Body"', allow_blank=True)
    goal_list = DataValidation(type="list", formula1='"Strength,Hypertrophy,Power,Work Capacity,Technique"', allow_blank=True)
    ws.add_data_validation(session_list)
    ws.add_data_validation(goal_list)
    session_list.add("D5:D404")
    goal_list.add("E5:E404")

    number_cols = {
        "G5:G404": (1, 10),
        "H5:H404": (1, 30),
        "I5:I404": (0, 1000),
        "J5:J404": (15, 300),
        "K5:K404": (1, 10),
    }
    for rng, (lo, hi) in number_cols.items():
        dv = DataValidation(type="whole", operator="between", formula1=lo, formula2=hi, allow_blank=True)
        ws.add_data_validation(dv)
        dv.add(rng)

    ws.conditional_formatting.add("K5:K404", ColorScaleRule(start_type="num", start_value=1, start_color="BBF7D0", end_type="num", end_value=10, end_color="FECACA"))
    ws.conditional_formatting.add("G5:G404", DataBarRule(start_type="num", start_value=1, end_type="num", end_value=10, color=BRAND_SKY))

    ws.auto_filter.ref = "B4:L404"
    set_col_widths(ws, {"B": 8, "C": 12, "D": 14, "E": 16, "F": 36, "G": 8, "H": 10, "I": 11, "J": 10, "K": 10, "L": 34})


def build_exercise_library(wb: Workbook) -> None:
    ws = wb.create_sheet("Exercise Library")
    configure_sheet(ws, freeze="B5", zoom=110)
    style_brand_banner(ws, start_row=1, start_col=2, end_col=14)
    style_title(ws, "B3", "Exercise Library", subtitle="5,200 entries for programming depth")

    headers = ["ID", "Category", "Exercise", "Equipment", "Level", "Focus", "Default Reps", "Default Rest", "Tempo", "Coaching Cue"]
    for i, h in enumerate(headers, start=2):
        ws.cell(row=4, column=i, value=h)
    style_headers(ws, 4, 2, 11)

    for r_idx, row in enumerate(EXERCISE_LIBRARY, start=5):
        for c_idx, value in enumerate(row, start=2):
            ws.cell(row=r_idx, column=c_idx, value=value)
            style_data_cell(ws.cell(row=r_idx, column=c_idx))

    zebra_rows(ws, 5, 5204, 2, 11)

    ws.conditional_formatting.add("H5:H5204", DataBarRule(start_type="num", start_value=0, end_type="num", end_value=180, color=BRAND_PURPLE))
    ws.conditional_formatting.add("G5:G5204", ColorScaleRule(start_type="num", start_value=4, start_color="BFDBFE", end_type="num", end_value=15, end_color="1D4ED8"))

    ws.auto_filter.ref = "B4:K5204"
    set_col_widths(ws, {
        "B": 8,
        "C": 14,
        "D": 34,
        "E": 14,
        "F": 14,
        "G": 14,
        "H": 12,
        "I": 12,
        "J": 12,
        "K": 70,
    })


def build_daily_log(wb: Workbook) -> None:
    ws = wb.create_sheet("Daily Log")
    configure_sheet(ws, freeze="B5")
    style_brand_banner(ws, start_row=1, start_col=2, end_col=14)
    style_title(ws, "B3", "Daily Training Log", subtitle="Execution tracker for every training day")

    headers = [
        "Date",
        "Day",
        "Session Completed",
        "Session Type",
        "Exercise",
        "Sets Done",
        "Reps Done",
        "Load Used",
        "Top Set",
        "Duration (min)",
        "Session RPE",
        "Mood",
        "Notes",
    ]
    for i, h in enumerate(headers, start=2):
        ws.cell(row=4, column=i, value=h)
    style_headers(ws, 4, 2, 14)

    start = date.today() - timedelta(days=30)
    day_labels = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"]

    for r in range(5, 2005):
        d = start + timedelta(days=r - 5)
        ws.cell(row=r, column=2, value=d.isoformat())
        ws.cell(row=r, column=3, value=day_labels[d.weekday()])
        for c in range(2, 15):
            style_data_cell(ws.cell(row=r, column=c))

    zebra_rows(ws, 5, 2004, 2, 14)

    yes_no = DataValidation(type="list", formula1='"Yes,No"', allow_blank=True)
