def build_body_metrics(wb: Workbook) -> None:
    ws = wb.create_sheet("Body Metrics")
    configure_sheet(ws, freeze="E6")
    style_brand_banner(ws, start_row=1, start_col=2, end_col=12)
    style_title(ws, "B3", "Body Metrics", subtitle="Weekly physique and performance metric tracking")

    style_section_header(ws, 5, 2, 4, "Current Snapshot")
    ws["B6"] = "Starting Weight"
    ws["B7"] = "Current Weight"
    ws["B8"] = "Total Change"
    ws["B9"] = "Target Weight"
    ws["B10"] = "Distance to Goal"

    ws["C8"] = "=IFERROR(C5-C6,0)"
    ws["C10"] = "=IFERROR(C6-C9,0)"

    for r in range(6, 11):
        ws[f"B{r}"].font = Font(bold=True, color=BRAND_BLUE)
        ws[f"B{r}"].fill = PatternFill(fill_type="solid", fgColor="E2E8F0")
        ws[f"B{r}"].border = MED_BORDER
        ws[f"C{r}"].border = MED_BORDER
        ws[f"C{r}"].alignment = Alignment(horizontal="center")
        ws[f"C{r}"].number_format = "0.0"

    ws["E5"] = "Date"
    ws["F5"] = "Weight"
    ws["G5"] = "Waist"
    ws["H5"] = "Chest"
    ws["I5"] = "Hip"
    ws["J5"] = "Body Fat %"
    ws["K5"] = "Resting HR"
    style_headers(ws, 5, 5, 11)

    for r in range(6, 406):
        for c in range(5, 12):
            style_data_cell(ws.cell(row=r, column=c))
        ws.cell(row=r, column=6).number_format = "0.0"
        ws.cell(row=r, column=7).number_format = "0.0"
        ws.cell(row=r, column=8).number_format = "0.0"
        ws.cell(row=r, column=9).number_format = "0.0"
        ws.cell(row=r, column=10).number_format = "0.0"

    zebra_rows(ws, 6, 405, 5, 11)

    ws.conditional_formatting.add("F6:F405", DataBarRule(start_type="num", start_value=90, end_type="num", end_value=350, color=BRAND_PURPLE))
    ws.conditional_formatting.add("J6:J405", ColorScaleRule(start_type="num", start_value=5, start_color="BBF7D0", end_type="num", end_value=35, end_color="FCA5A5"))

    line = LineChart()
    line.title = "Weight Trend"
    line.style = 10
    line.y_axis.title = "Weight"
    line.x_axis.title = "Date"
    data = Reference(ws, min_col=6, min_row=5, max_row=405)
    cats = Reference(ws, min_col=5, min_row=6, max_row=405)
    line.add_data(data, titles_from_data=True)
    line.set_categories(cats)
    line.height = 7
    line.width = 12
    ws.add_chart(line, "B13")

    ws.auto_filter.ref = "E5:K405"
    set_col_widths(ws, {"B": 20, "C": 12, "D": 2, "E": 13, "F": 10, "G": 10, "H": 10, "I": 10, "J": 12, "K": 12, "L": 2})


def build_recovery_tracker(wb: Workbook) -> None:
    ws = wb.create_sheet("Recovery Tracker")
    configure_sheet(ws, freeze="B5")
    style_brand_banner(ws, start_row=1, start_col=2, end_col=11)
    style_title(ws, "B3", "Recovery Tracker", subtitle="Sleep, stress, and readiness monitoring")

    headers = ["Date", "Sleep Hours", "Sleep Quality (1-10)", "Steps", "Stress (1-10)", "Soreness (1-10)", "Hydration (L)", "Recovery Score", "Notes"]
    for i, h in enumerate(headers, start=2):
        ws.cell(row=4, column=i, value=h)
    style_headers(ws, 4, 2, 10)

    for r in range(5, 2005):
        for c in range(2, 11):
            style_data_cell(ws.cell(row=r, column=c))
        ws.cell(row=r, column=9, value=f"=IF(C{r}=\"\",\"\",ROUND((C{r}*3 + D{r}*2 + IF(F{r}=\"\",0,11-F{r}) + IF(G{r}=\"\",0,11-G{r}) + H{r}*2),1))")

    zebra_rows(ws, 5, 2004, 2, 10)

    numeric_ranges = {
        "C5:C2004": (0, 14),
        "D5:D2004": (1, 10),
        "E5:E2004": (0, 50000),
        "F5:F2004": (1, 10),
        "G5:G2004": (1, 10),
        "H5:H2004": (0, 10),
    }
    for rng, (lo, hi) in numeric_ranges.items():
        dv = DataValidation(type="whole", operator="between", formula1=lo, formula2=hi, allow_blank=True)
        ws.add_data_validation(dv)
        dv.add(rng)

    ws.conditional_formatting.add("I5:I2004", IconSetRule(icon_style="3TrafficLights1", type="num", values=[35, 55, 75]))
    ws.conditional_formatting.add("C5:C2004", ColorScaleRule(start_type="num", start_value=4, start_color="FECACA", end_type="num", end_value=9, end_color="BBF7D0"))

    ws.auto_filter.ref = "B4:J2004"
    set_col_widths(ws, {"B": 12, "C": 12, "D": 18, "E": 11, "F": 12, "G": 14, "H": 12, "I": 12, "J": 35, "K": 2})


def build_nutrition(wb: Workbook) -> None:
    ws = wb.create_sheet("Nutrition")
    configure_sheet(ws, freeze="B5")
    style_brand_banner(ws, start_row=1, start_col=2, end_col=12)
    style_title(ws, "B3", "Nutrition Log", subtitle="Fuel quality directly impacts output")

