def build_pr_tracker(wb: Workbook) -> None:
    ws = wb.create_sheet("PR Tracker")
    configure_sheet(ws, freeze="B5")
    style_brand_banner(ws, start_row=1, start_col=2, end_col=11)
    style_title(ws, "B3", "Personal Record Tracker", subtitle="Capture objective strength progression")

    headers = ["Date", "Lift", "Category", "Weight", "Reps", "Estimated 1RM", "Body Weight", "Relative Strength", "Notes"]
    for i, h in enumerate(headers, start=2):
        ws.cell(row=4, column=i, value=h)
    style_headers(ws, 4, 2, 10)

    lifts = ["Back Squat", "Bench Press", "Deadlift", "Overhead Press", "Weighted Pull-Up", "Barbell Row"]

    for r in range(5, 1205):
        ws.cell(row=r, column=3, value=lifts[(r - 5) % len(lifts)])
        ws.cell(row=r, column=4, value="Compound")
        ws.cell(row=r, column=7, value=f"=IF(OR(E{r}=\"\",F{r}=\"\"),\"\",ROUND(E{r}*(1+F{r}/30),1))")
        ws.cell(row=r, column=9, value=f"=IF(OR(G{r}=\"\",H{r}=\"\"),\"\",ROUND(G{r}/H{r},2))")
        for c in range(2, 11):
            style_data_cell(ws.cell(row=r, column=c))

    zebra_rows(ws, 5, 1204, 2, 10)

    lift_list = DataValidation(type="list", formula1='"Back Squat,Bench Press,Deadlift,Overhead Press,Weighted Pull-Up,Barbell Row"', allow_blank=True)
    category = DataValidation(type="list", formula1='"Compound,Accessory,Conditioning"', allow_blank=True)
    ws.add_data_validation(lift_list)
    ws.add_data_validation(category)
    lift_list.add("C5:C1204")
    category.add("D5:D1204")

    for rng, lo, hi in [
        ("E5:E1204", 0, 1500),
        ("F5:F1204", 1, 30),
        ("H5:H1204", 80, 500),
    ]:
        dv = DataValidation(type="whole", operator="between", formula1=lo, formula2=hi, allow_blank=True)
        ws.add_data_validation(dv)
        dv.add(rng)

    ws.conditional_formatting.add("G5:G1204", DataBarRule(start_type="num", start_value=0, end_type="num", end_value=1800, color=BRAND_GOLD))
    ws.conditional_formatting.add("I5:I1204", ColorScaleRule(start_type="num", start_value=0.5, start_color="FECACA", end_type="num", end_value=3.0, end_color="BBF7D0"))

    ws.auto_filter.ref = "B4:J1204"
    set_col_widths(ws, {"B": 12, "C": 22, "D": 12, "E": 10, "F": 8, "G": 14, "H": 12, "I": 16, "J": 36})


def build_habit_tracker(wb: Workbook) -> None:
    ws = wb.create_sheet("Habit Tracker")
    configure_sheet(ws, freeze="B4")
    style_brand_banner(ws, start_row=1, start_col=2, end_col=16)
    style_title(ws, "B3", "Habit Tracker", subtitle="Daily behavior scorecard")

    headers = ["Date", "Train", "Nutrition", "Hydration", "Sleep", "Steps", "Mobility", "Journal", "No Alcohol", "Morning Walk", "Read", "Meditate", "Recovery Work", "Daily Score"]
    for i, h in enumerate(headers, start=2):
        ws.cell(row=4, column=i, value=h)
    style_headers(ws, 4, 2, 15)

    for r in range(5, 1205):
        ws.cell(row=r, column=15, value=f"=SUM(C{r}:N{r})")
        for c in range(2, 16):
            style_data_cell(ws.cell(row=r, column=c))

    zebra_rows(ws, 5, 1204, 2, 15)

    binary = DataValidation(type="list", formula1='"1,0"', allow_blank=True)
    ws.add_data_validation(binary)
    for col in "CDEFGHIJKLMN":
        binary.add(f"{col}5:{col}1204")

    ws.conditional_formatting.add("O5:O1204", IconSetRule(icon_style="5Arrows", type="num", values=[3, 6, 8, 10, 12]))
    ws.conditional_formatting.add("O5:O1204", DataBarRule(start_type="num", start_value=0, end_type="num", end_value=12, color=BRAND_CYAN))

    ws.auto_filter.ref = "B4:O1204"
    set_col_widths(ws, {"B": 12, "C": 7, "D": 10, "E": 10, "F": 7, "G": 7, "H": 10, "I": 8, "J": 10, "K": 12, "L": 8, "M": 8, "N": 13, "O": 12})


def build_weekly_planner(wb: Workbook) -> None:
    ws = wb.create_sheet("Weekly Planner")
    configure_sheet(ws, zoom=130)
    style_brand_banner(ws, start_row=1, start_col=2, end_col=12)
    style_title(ws, "B3", "Weekly Execution Planner", subtitle="Tactical week-level planning page")

    days = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"]
    start_row = 6
    for i, d in enumerate(days):
        r = start_row + i * 3
        style_section_header(ws, r, 2, 10, d)
        ws.merge_cells(start_row=r + 1, start_column=2, end_row=r + 2, end_column=6)
        ws.merge_cells(start_row=r + 1, start_column=7, end_row=r + 2, end_column=10)

        ws.cell(row=r + 1, column=2, value="Top Priorities")
        ws.cell(row=r + 1, column=7, value="Training Focus")

        for rr in [r + 1, r + 2]:
            for cc in range(2, 11):
                ws.cell(row=rr, column=cc).border = THIN_BORDER
                ws.cell(row=rr, column=cc).alignment = Alignment(vertical="top", wrap_text=True)

    set_col_widths(ws, {"B": 20, "C": 20, "D": 20, "E": 20, "F": 20, "G": 20, "H": 20, "I": 20, "J": 20})


def build_instructions(wb: Workbook) -> None:
    ws = wb.create_sheet("Instructions")
    configure_sheet(ws, zoom=120)
    style_brand_banner(ws, start_row=1, start_col=2, end_col=12)
    style_title(ws, "B3", "Instructions", subtitle="Use this system like a professional")

    blocks = [
        ("Setup", [
            "1) Open Start Here and read the mission and process.",
            "2) In Body Metrics, enter your starting weight (C5), current weight (C6), and target (C9).",
            "3) In Program Builder, design your weekly split and exercise selection.",
        ]),
        ("Daily Execution", [
            "1) Log every training day in Daily Log (date, completion, exercise, duration, RPE).",
            "2) Fill Recovery Tracker with sleep, steps, stress, hydration, and soreness.",
            "3) Fill Nutrition daily to keep output and recovery aligned.",
        ]),
        ("Weekly Review", [
            "1) Check Dashboard KPIs and completion trend.",
            "2) Review PR Tracker for objective progression.",
            "3) Review Habit Tracker score totals and improve weakest habit.",
            "4) Use Weekly Planner for tactical priorities before each week begins.",
        ]),
        ("Non-Negotiable Standards", [
            "- No blank weeks.",
            "- No random training: plan before execution.",
            "- No skipped recovery data.",
            "- Process over motivation. Consistency over intensity spikes.",
        ]),
    ]

    row = 6
    for title, items in blocks:
        style_section_header(ws, row, 2, 11, title)
        row += 1
        for item in items:
            ws.cell(row=row, column=2, value=item)
            ws.merge_cells(start_row=row, start_column=2, end_row=row, end_column=11)
            ws.cell(row=row, column=2).border = THIN_BORDER
            ws.cell(row=row, column=2).alignment = Alignment(wrap_text=True)
            ws.cell(row=row, column=2).fill = PatternFill(fill_type="solid", fgColor="F8FAFC" if row % 2 == 0 else "FFFFFF")
            row += 1
        row += 1

    set_col_widths(ws, {"B": 24, "C": 24, "D": 24, "E": 24, "F": 24, "G": 24, "H": 24, "I": 24, "J": 24, "K": 24, "L": 2})


def build_workbook(output_path: str) -> None:
    wb = Workbook()
    set_workbook_defaults(wb)

    build_cover_sheet(wb)
    build_dashboard(wb)
    build_program_builder(wb)
    build_exercise_library(wb)
    build_daily_log(wb)
    build_body_metrics(wb)
    build_recovery_tracker(wb)
    build_nutrition(wb)
    build_pr_tracker(wb)
    build_habit_tracker(wb)
    build_weekly_planner(wb)
    build_instructions(wb)

    wb.save(output_path)


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Generate Ethan's elite workout workbook.")
    parser.add_argument(
        "--output",
        default="Ethan_Elite_Workout_System.xlsx",
        help="Output filename (default: Ethan_Elite_Workout_System.xlsx)",
    )
    return parser.parse_args()


def main() -> None:
    args = parse_args()
    build_workbook(args.output)
    print(f"Elite workbook created: {args.output}")


if __name__ == "__main__":
    main()
